import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Axios, { COURSES } from "../../Api/Api";
import "../../Styles/CourseDetails.css";
import Cookie from "cookie-universal";

export default function CourseDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const cookie = Cookie();  // ← أضف هذا السطر!

  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [enrolled, setEnrolled] = useState(false);
  const [enrollLoading, setEnrollLoading] = useState(false);
  const [userRole, setUserRole] = useState(null);

  useEffect(() => {
    Axios.get(`/${COURSES}/${id}`)
      .then((res) => {
        console.log("Course Details:", res.data);
        setCourse(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error:", err);
        setError("الكورس غير موجود");
        setLoading(false);
      });
  }, [id]);

  useEffect(() => {
    if (course) {
      checkEnrollment();
    }
  }, [course]);

  async function checkEnrollment() {
    try {
      const token = cookie.get("educational-token");  // ← عدّل هنا
      if (!token) return;

      const res = await Axios.get(`/courses/${id}/check-enrollment`);
      setEnrolled(res.data.enrolled);
    } catch (err) {
      console.error(err);
    }
  }

  async function handleEnrollment() {
    const token = cookie.get("educational-token");  // ← عدّل هنا
    if (!token) {
      alert("يجب تسجيل الدخول أولاً");
      navigate("/login");
      return;
    }

    setEnrollLoading(true);

    try {
      if (enrolled) {
        await Axios.delete(`/courses/${id}/enroll`);
        setEnrolled(false);
        alert("تم إلغاء التسجيل");
      } else {
        await Axios.post(`/courses/${id}/enroll`);
        setEnrolled(true);
        alert("تم التسجيل بنجاح! 🎉");
      }
    } catch (err) {
      alert(err.response?.data?.message || "حدث خطأ");
    } finally {
      setEnrollLoading(false);
    }
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري تحميل التفاصيل...</p>
      </div>
    );
  }

  if (error || !course) {
    return (
      <div className="error-container">
        <h2>😕 {error}</h2>
        <button onClick={() => navigate("/courses")} className="back-btn">
          العودة للكورسات
        </button>
      </div>
    );
  }

  const imageUrl = course.image?.startsWith("http")
    ? course.image
    : `http://127.0.0.1:8000${course.image}`;

  return (
    <div className="course-details-page">
      {/* Hero Section */}
      <section className="course-hero">
        <div className="container">
          <button onClick={() => navigate(-1)} className="back-link">
            ← العودة
          </button>

          <div className="course-hero-content">
            <div className="course-hero-info">
              <h1 className="course-hero-title">{course.title}</h1>
              <p className="course-hero-description">{course.description}</p>

              <div className="course-meta">
                <div className="meta-item">
                  <span className="meta-icon">⭐</span>
                  <span className="meta-text">{course.rating} تقييم</span>
                </div>

                <div className="meta-item price-tag">
                  <span className="meta-icon">💰</span>
                  <span className="meta-text price">${course.price}</span>
                </div>
              </div>

              {/* معلومات المدرس */}
              {course.instructor && (
                <div
                  className="instructor-card-inline"
                  onClick={() =>
                    navigate(`/instructors/${course.instructor.id}`)
                  }
                >
                  <div className="instructor-avatar-small">
                    <img
                      src={
                        course.instructor.avatar ||
                        "https://via.placeholder.com/100"
                      }
                      alt={course.instructor.name}
                      onError={(e) => {
                        e.target.src =
                          "https://via.placeholder.com/100?text=No+Image";
                      }}
                    />
                  </div>
                  <div className="instructor-info-small">
                    <p className="label">المدرب</p>
                    <h4>{course.instructor.name}</h4>
                    <p className="spec">{course.instructor.specialization}</p>
                    <div className="instructor-rating">
                      <span>⭐ {course.instructor.rating}</span>
                      <span>
                        • {course.instructor.experience_years} سنوات خبرة
                      </span>
                    </div>
                  </div>
                </div>
              )}

              {/* زر التسجيل الرئيسي */}
              <button
                onClick={handleEnrollment}
                disabled={enrollLoading}
                className={enrolled ? "unenroll-btn" : "enroll-btn"}
              >
                {enrollLoading
                  ? "جاري المعالجة..."
                  : enrolled
                    ? "إلغاء التسجيل ❌"
                    : "سجّل الآن في الكورس ✅"}
              </button>
            </div>

            <div className="course-hero-image">
              <img src={imageUrl} alt={course.title} />
            </div>
          </div>
        </div>
      </section>

      {/* Course Content Section */}
      <section className="course-content">
        <div className="container">
          <div className="content-grid">
            {/* المحتوى الرئيسي */}
            <div className="main-content">
              <div className="content-card">
                <h2>📚 عن الكورس</h2>
                <p>{course.description}</p>
              </div>

              <div className="content-card">
                <h2>🎯 ماذا ستتعلم؟</h2>
                <ul className="learning-list">
                  <li>فهم شامل للموضوع من الصفر</li>
                  <li>تطبيق عملي على مشاريع حقيقية</li>
                  <li>أفضل الممارسات والأدوات الحديثة</li>
                  <li>شهادة إتمام معتمدة</li>
                </ul>
              </div>

              <div className="content-card">
                <h2>👥 لمن هذا الكورس؟</h2>
                <ul className="audience-list">
                  <li>المبتدئين الذين يرغبون بالبدء من الصفر</li>
                  <li>المطورين الذين يريدون تطوير مهاراتهم</li>
                  <li>الطلاب والخريجين الجدد</li>
                </ul>
              </div>
            </div>

            {/* Sidebar */}
            <aside className="sidebar">
              <div className="sidebar-card">
                <h3>📊 معلومات الكورس</h3>
                <div className="info-list">
                  <div className="info-item">
                    <span className="info-label">السعر:</span>
                    <span className="info-value price">${course.price}</span>
                  </div>
                  <div className="info-item">
                    <span className="info-label">التقييم:</span>
                    <span className="info-value">⭐ {course.rating}</span>
                  </div>
                  {course.instructor && (
                    <div className="info-item">
                      <span className="info-label">المدرب:</span>
                      <span className="info-value">
                        {course.instructor.name}
                      </span>
                    </div>
                  )}
                  <div className="info-item">
                    <span className="info-label">المستوى:</span>
                    <span className="info-value">جميع المستويات</span>
                  </div>
                </div>
                
                {/* زر التسجيل في Sidebar */}
                <button
                  onClick={handleEnrollment}
                  disabled={enrollLoading}
                  className={enrolled ? "unenroll-btn sidebar-enroll-btn" : "enroll-btn sidebar-enroll-btn"}
                >
                  {enrollLoading
                    ? "جاري المعالجة..."
                    : enrolled
                      ? "إلغاء التسجيل ❌"
                      : "سجّل الآن"}
                </button>
              </div>

              <div className="sidebar-card">
                <h3>✨ المميزات</h3>
                <ul className="features-list">
                  <li>✅ وصول مدى الحياة</li>
                  <li>✅ شهادة إتمام</li>
                  <li>✅ دعم فني مباشر</li>
                  <li>✅ تحديثات مجانية</li>
                </ul>
              </div>
            </aside>
          </div>
        </div>
      </section>
    </div>
  );
}
